using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;
using Newtonsoft.Json;

namespace MyFunctionApp
{
    public static class MyFunction
    {
        [FunctionName("MyFunction")]
        public static async Task<IActionResult> Run(
            [HttpTrigger(AuthorizationLevel.Anonymous, "get", "post", Route = null)] HttpRequest req,
            ILogger log)
        {
            log.LogInformation($"C# HTTP trigger function processed a request. RequestUri={req.RequestUri}");

            // Log all HTTP request headers and body content
            foreach (var header in req.Headers)
            {
                log.LogInformation($"Header: {header.Key} = {header.Value}");
            }

            string requestBody = await new StreamReader(req.Body).ReadToEndAsync();
            log.LogInformation($"Request body: {requestBody}");

            // Log all database queries with parameters
            var dbQueries = new List<string>();
            foreach (var query in req.Query)
            {
                log.LogInformation($"Query: {query.Key} = {query.Value}");
                dbQueries.Add(query.Key);
            }

            // Log full exception details
            try
            {
                // Your function implementation goes here
            }
            catch (Exception ex)
            {
                log.LogError($"Exception: {ex.Message}");
                log.LogError(ex, "Error occurred while processing request.");
            }

            return new OkResult();
